import React, { useState, useEffect } from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  Button,
  Box,
  CircularProgress,
  Chip,
  Rating,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
} from '@mui/material';
import axios from 'axios';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import PeopleIcon from '@mui/icons-material/People';

function Pitches() {
  const [pitches, setPitches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [selectedPitch, setSelectedPitch] = useState(null);
  const [bookingData, setBookingData] = useState({
    date: '',
    time: '',
    duration: 1,
  });

  useEffect(() => {
    const fetchPitches = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/pitches');
        setPitches(response.data);
        setLoading(false);
      } catch (err) {
        setError('Failed to fetch pitches');
        setLoading(false);
      }
    };

    fetchPitches();
  }, []);

  const handleBooking = (pitch) => {
    setSelectedPitch(pitch);
  };

  const handleClose = () => {
    setSelectedPitch(null);
    setBookingData({ date: '', time: '', duration: 1 });
  };

  const handleBookingSubmit = async () => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        window.location.href = '/login';
        return;
      }

      await axios.post(
        'http://localhost:5000/api/bookings',
        {
          pitch_id: selectedPitch.pitch_id,
          booking_date: bookingData.date,
          booking_time: bookingData.time,
          duration: bookingData.duration,
        },
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      handleClose();
      // Show success message or redirect to bookings page
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to book pitch');
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Container>
        <Typography color="error" align="center" sx={{ mt: 4 }}>
          {error}
        </Typography>
      </Container>
    );
  }

  return (
    <Box sx={{ py: 8, bgcolor: 'background.default' }}>
      <Container maxWidth="lg">
        <Typography variant="h3" component="h1" gutterBottom align="center" sx={{ mb: 6 }}>
          Available Pitches
        </Typography>
        <Grid container spacing={4}>
          {pitches.map((pitch) => (
            <Grid item key={pitch.pitch_id} xs={12} sm={6} md={4}>
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  transition: 'transform 0.2s',
                  '&:hover': {
                    transform: 'translateY(-8px)',
                  },
                }}
              >
                <CardMedia
                  component="img"
                  height="200"
                  image={pitch.image_url || 'https://via.placeholder.com/300x200?text=Cricket+Pitch'}
                  alt={pitch.pitch_name}
                />
                <CardContent sx={{ flexGrow: 1 }}>
                  <Typography gutterBottom variant="h5" component="h2">
                    {pitch.pitch_name}
                  </Typography>
                  <Box sx={{ mb: 2 }}>
                    <Rating value={4.5} precision={0.5} readOnly />
                    <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                      {pitch.description}
                    </Typography>
                  </Box>
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                    <LocationOnIcon sx={{ mr: 1, color: 'primary.main' }} />
                    <Typography variant="body2">{pitch.location}</Typography>
                  </Box>
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                    <AccessTimeIcon sx={{ mr: 1, color: 'primary.main' }} />
                    <Typography variant="body2">Available 24/7</Typography>
                  </Box>
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                    <PeopleIcon sx={{ mr: 1, color: 'primary.main' }} />
                    <Typography variant="body2">Capacity: {pitch.capacity || '22 players'}</Typography>
                  </Box>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                    <Typography variant="h6" color="primary">
                      ₹{pitch.price_per_hour}/hour
                    </Typography>
                    <Chip label={pitch.status || 'Available'} color="success" size="small" />
                  </Box>
                  <Button
                    variant="contained"
                    color="primary"
                    fullWidth
                    onClick={() => handleBooking(pitch)}
                  >
                    Book Now
                  </Button>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>

        {/* Booking Dialog */}
        <Dialog open={Boolean(selectedPitch)} onClose={handleClose} maxWidth="sm" fullWidth>
          <DialogTitle>Book {selectedPitch?.pitch_name}</DialogTitle>
          <DialogContent>
            <Box sx={{ mt: 2 }}>
              <TextField
                fullWidth
                label="Date"
                type="date"
                value={bookingData.date}
                onChange={(e) => setBookingData({ ...bookingData, date: e.target.value })}
                InputLabelProps={{ shrink: true }}
                sx={{ mb: 2 }}
              />
              <TextField
                fullWidth
                label="Time"
                type="time"
                value={bookingData.time}
                onChange={(e) => setBookingData({ ...bookingData, time: e.target.value })}
                InputLabelProps={{ shrink: true }}
                sx={{ mb: 2 }}
              />
              <TextField
                fullWidth
                label="Duration (hours)"
                type="number"
                value={bookingData.duration}
                onChange={(e) => setBookingData({ ...bookingData, duration: e.target.value })}
                InputProps={{ inputProps: { min: 1, max: 24 } }}
                sx={{ mb: 2 }}
              />
              <Typography variant="h6" color="primary" gutterBottom>
                Total Amount: ₹{selectedPitch ? selectedPitch.price_per_hour * bookingData.duration : 0}
              </Typography>
            </Box>
          </DialogContent>
          <DialogActions>
            <Button onClick={handleClose}>Cancel</Button>
            <Button onClick={handleBookingSubmit} variant="contained" color="primary">
              Confirm Booking
            </Button>
          </DialogActions>
        </Dialog>
      </Container>
    </Box>
  );
}

export default Pitches;
